/**
 * wp_logo_data.js
 * Embedded Bargig logo as a Data URI.
 * The logo itself includes the rounded translucent background,
 * so all site locations can use the same ready-made visual.
 * Exposes:
 *   window.WP_LOGO_DATA_URI
 *   window.applyWardrobeProLogo()
 */
/* global window, document, MutationObserver */
(function () {
  'use strict';

  var DATA_URI =
    'data:image/png;base64,';

  window.WP_LOGO_DATA_URI = DATA_URI;

  function applyWardrobeProLogo() {
    try {
      var uri = window.WP_LOGO_DATA_URI;
      if (!uri || typeof uri !== 'string') return;

      var nodes = document.querySelectorAll('img.header-logo, img[data-brand-logo="1"], img[data-wp-logo="1"], #wpHeaderLogo');
      for (var i = 0; i < nodes.length; i += 1) {
        var img = nodes[i];
        img.setAttribute('src', uri);
        if (!img.getAttribute('alt')) img.setAttribute('alt', 'לוגו רהיטי ברגיג');
        img.decoding = 'async';
      }
    } catch (_e) {
      // silent
    }
  }

  window.applyWardrobeProLogo = applyWardrobeProLogo;

  function startLogoObserver() {
    try {
      var root = document && document.documentElement;
      if (!root || typeof MutationObserver !== 'function') return;

      var scheduled = false;
      function scheduleApply() {
        if (scheduled) return;
        scheduled = true;
        setTimeout(function () {
          scheduled = false;
          applyWardrobeProLogo();
        }, 0);
      }

      var obs = new MutationObserver(function (mutations) {
        for (var i = 0; i < mutations.length; i += 1) {
          var m = mutations[i];
          if (m.type === 'childList' && m.addedNodes && m.addedNodes.length) {
            scheduleApply();
            return;
          }
          if (m.type === 'attributes' && m.attributeName === 'src') {
            scheduleApply();
            return;
          }
        }
      });

      obs.observe(root, {
        subtree: true,
        childList: true,
        attributes: true,
        attributeFilter: ['src'],
      });

      setTimeout(applyWardrobeProLogo, 25);
      setTimeout(applyWardrobeProLogo, 150);
      setTimeout(applyWardrobeProLogo, 600);
      setTimeout(function () {
        try { obs.disconnect(); } catch (_e) {}
      }, 10000);
    } catch (_e) {
      // ignore
    }
  }

  if (document && document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function () {
      applyWardrobeProLogo();
      startLogoObserver();
    });
  } else {
    applyWardrobeProLogo();
    startLogoObserver();
  }
})();
